var e=[{id:`L2_1`,type:`dialog`,speaker:`MAVKA_DOLL_NULL_NULL`,text:{KOREA:`난 다시 싸울 거야. 누군가의 명령이 아닌 내 의지로.`,JPN:`また私は戦う。誰かの命令ではなく、私の意思で。`,ENG:`I'll fight again. Not because of someone's orders, by on my accord.`,TWN:`我會再次戰鬥。這次不是奉某人之命，而是我自己的意思。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAVKA_DOLL_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MAVKA_DOLL_NULL_NULL`,text:{KOREA:`내가 받게 된 이 힘은, 많은 사람들을 지키기 위해 사용하기로 결심했어.`,JPN:`私が手にした力は、多くの人を守るために使うと決めたんだ。`,ENG:`This power that I received, I've decided to use it to protect many people.`,TWN:`我決定將我獲得的這份力量，用來保護更多的人。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAVKA_DOLL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MAVKA_DOLL_NULL_NULL`,text:{KOREA:`당신도 분명… 나랑 같은 마음이겠지?`,JPN:`あなたもきっと、私と同じ気持ちだよね？`,ENG:`I'm sure... you feel the same way as I do, right?`,TWN:`我相信…你也和我一樣吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAVKA_DOLL_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};